const GT_AMERICA_B64='';
const GT_SUPER_B64='';
// --- VIEW SWITCHING ---
const toolLabels={offer:'offer builder',price:'price calculator',confirm:'booking confirmation',invoice:'invoice generator'};
let openTabs=['home'];
let navHistory=[];
let currentView='home';
let cfInited=false;
let quickStartOpen=false;

const quickStartTools=['offer','price','confirm'];

function renderTabs(){
  const bar=document.getElementById('tabs-bar');
  const dynamicTabs=openTabs.map(name=>{
    const active=name===currentView?' active':'';
    const dot=name!=='home'?'<span class="tab-dot"></span>':'';
    const close=name!=='home'?`<span class="tab-close" onclick="closeTab('${name}',event)">✕</span>`:'';
    const label=name==='home'?'home':toolLabels[name];
    return `<button class="tab${active}" onclick="showView('${name}')">${dot}${label}${close}</button>`;
  }).join('');
  const dropdownItems=quickStartTools.map(name=>`
    <button class="qs-item" onclick="openTool('${name}');closeQuickStart()">
      <span class="tab-dot"></span>${toolLabels[name]}
    </button>`).join('');
  const qs=`<div class="qs-wrap" id="qs-wrap">
    <button class="tab qs-tab${quickStartOpen?' qs-open':''}" onclick="toggleQuickStart(event)">quick start ▾</button>
    <div class="qs-menu${quickStartOpen?' open':''}">
      ${dropdownItems}
    </div>
  </div>`;
  bar.innerHTML=dynamicTabs+qs;
}
function toggleQuickStart(e){
  e.stopPropagation();
  quickStartOpen=!quickStartOpen;
  renderTabs();
}
function closeQuickStart(){
  quickStartOpen=false;
  renderTabs();
}
function openTool(name){
  if(!openTabs.includes(name)) openTabs.push(name);
  showView(name);
}
function closeTab(name,e){
  e.stopPropagation();
  openTabs=openTabs.filter(t=>t!==name);
  if(currentView===name){
    const fallback=[...navHistory].reverse().find(h=>openTabs.includes(h))||'home';
    showView(fallback,true);
  } else {
    renderTabs();
  }
}
function showView(name,fromBack=false){
  if(!fromBack&&name!==currentView) navHistory.push(currentView);
  currentView=name;
  document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));
  document.getElementById('view-'+name).classList.add('active');
  if(name!=='home'&&!openTabs.includes(name)) openTabs.push(name);
  renderTabs();
  if(name==='price'&&!fxRates)fetchFX();
  if(name==='confirm'&&!cfInited){cfInited=true;initConfirm();}
}
function goBack(){
  if(navHistory.length>0){
    const prev=navHistory.pop();
    showView(prev,true);
  } else {
    showView('home',true);
  }
}
renderTabs();
document.documentElement.style.setProperty('--nav-h', document.querySelector('nav').offsetHeight+'px');

// --- CALCULATORS ---
function fmt(n){return'€'+n.toLocaleString('fr-FR',{minimumFractionDigits:2,maximumFractionDigits:2});}

let commMode='gross';
function setCommMode(mode){
  commMode=mode;
  document.getElementById('comm-tog-gross').classList.toggle('active',mode==='gross');
  document.getElementById('comm-tog-ht').classList.toggle('active',mode==='ht');
  calcComm();
}

function getVat(){
  const sel=document.getElementById('c-country').value;
  if(sel==='custom') return parseFloat(document.getElementById('c-vat-custom').value)||0;
  return parseFloat(sel)||0;
}

const cCountry=document.getElementById('c-country');
if(cCountry) cCountry.addEventListener('change',function(){
  document.getElementById('c-vat-custom').style.display=this.value==='custom'?'block':'none';
  calcComm();
});

function calcComm(){
  const gross=parseFloat(document.getElementById('c-gross').value);
  const pct=parseFloat(document.getElementById('c-pct').value);
  if(isNaN(gross)||isNaN(pct)){
    document.getElementById('c-result').textContent='—';
    document.getElementById('c-net').textContent='—';
    document.getElementById('c-ht').textContent='—';
    return;
  }
  const vat=getVat();
  const ht=gross/(1+vat/100);
  document.getElementById('c-ht').textContent=fmt(ht);
  const base=commMode==='ht'?ht:gross;
  const comm=base*pct/100;
  document.getElementById('c-result').textContent=fmt(comm);
  document.getElementById('c-net').textContent=fmt(ht-comm);
}

function calcTopup(){
  const n=parseFloat(document.getElementById('t-net').value);
  const p=parseFloat(document.getElementById('t-pct').value);
  if(isNaN(n)||isNaN(p)){document.getElementById('t-result').textContent='—';document.getElementById('t-margin').textContent='—';return;}
  const client=n*(1+p/100);
  document.getElementById('t-result').textContent=fmt(client);
  document.getElementById('t-margin').textContent=fmt(client-n);
}

function calcPct(){
  const a=parseFloat(document.getElementById('p-amount').value);
  const p=parseFloat(document.getElementById('p-pct').value);
  if(isNaN(a)||isNaN(p)){document.getElementById('p-result').textContent='—';document.getElementById('p-total').textContent='—';return;}
  const fee=a*p/100;
  document.getElementById('p-result').textContent=fmt(fee);
  document.getElementById('p-total').textContent=fmt(a+fee);
}

// FX
let fxRates=null;
async function fetchFX(){
  document.getElementById('fx-rate-label').textContent='Loading live rates...';
  try{
    const res=await fetch('https://open.er-api.com/v6/latest/EUR');
    const data=await res.json();
    if(data.result==='success'){
      fxRates=data.rates;
      const d=new Date(data.time_last_update_utc);
      document.getElementById('fx-rate-label').textContent=`Live rates · updated ${d.toLocaleDateString('en-GB',{day:'numeric',month:'short',year:'numeric'})}`;
      calcFX();
    }
  }catch(e){
    document.getElementById('fx-rate-label').textContent='Could not load rates — check connection';
  }
}

function calcFX(){
  if(!fxRates){document.getElementById('fx-result').textContent='—';return;}
  const amount=parseFloat(document.getElementById('fx-amount').value);
  const from=document.getElementById('fx-from').value;
  const to=document.getElementById('fx-to').value;
  if(isNaN(amount)){document.getElementById('fx-result').textContent='—';document.getElementById('fx-rate-display').textContent='—';return;}
  const inEur=amount/fxRates[from];
  const converted=inEur*fxRates[to];
  const rate=fxRates[to]/fxRates[from];
  document.getElementById('fx-result').textContent=converted.toLocaleString('fr-FR',{minimumFractionDigits:2,maximumFractionDigits:2})+' '+to;
  document.getElementById('fx-rate-display').textContent=rate.toFixed(4);
}

// --- CALENDAR ---
const MONTHS=['January','February','March','April','May','June','July','August','September','October','November','December'];
const MSHORT=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const DNAMES=['Su','Mo','Tu','We','Th','Fr','Sa'];
let cals={ci:{y:2026,m:3},co:{y:2026,m:3}};
let picked={ci:null,co:null};
let inp={ci:'d-in',co:'d-out'};

function tc(id){
  const pop=document.getElementById(id);
  const was=pop.classList.contains('open');
  document.querySelectorAll('.cal-pop').forEach(p=>p.classList.remove('open'));
  if(!was){rc(id);pop.classList.add('open');}
}
function rc(id){
  const{y,m}=cals[id];
  const first=new Date(y,m,1).getDay();
  const dim=new Date(y,m+1,0).getDate();
  const td=new Date();
  const s=picked[id];
  let h=`<div class="cal-nav"><button onclick="cn('${id}',-1)">‹</button><span>${MONTHS[m]} ${y}</span><button onclick="cn('${id}',1)">›</button></div><div class="cal-grid">`;
  DNAMES.forEach(d=>h+=`<div class="cdn">${d}</div>`);
  for(let i=0;i<first;i++)h+=`<div class="cd em"></div>`;
  for(let d=1;d<=dim;d++){
    const it=d===td.getDate()&&m===td.getMonth()&&y===td.getFullYear();
    const is=s&&s.d===d&&s.m===m&&s.y===y;
    h+=`<div class="cd${it?' td':''}${is?' sel':''}" onclick="pd('${id}',${y},${m},${d})">${d}</div>`;
  }
  h+=`</div>`;
  document.getElementById(id).innerHTML=h;
}
function cn(id,dir){
  let{y,m}=cals[id];m+=dir;
  if(m<0){m=11;y--;}if(m>11){m=0;y++;}
  cals[id]={y,m};rc(id);
}
function pd(id,y,m,d){
  picked[id]={y,m,d};
  document.getElementById(inp[id]).value=`${d} ${MSHORT[m]}`;
  document.getElementById(id).classList.remove('open');
  if(id==='ci'){cals.co={y,m};rc('co');}
}
document.addEventListener('click',e=>{
  if(!e.target.closest('.cal-wrap'))document.querySelectorAll('.cal-pop').forEach(p=>p.classList.remove('open'));
  hotels.forEach(h=>{if(!e.target.closest('#hdr-'+h.id))closeSug(h.id);});
  if(!e.target.closest('.qs-wrap')&&quickStartOpen)closeQuickStart();
});

